/**
 * @fileoverview Milestone component definition for JIT pipeline.
 *
 * @module module/Milestone.def
 */

import razyui from '../index.js';
import { PART } from './Milestone/constants.js';

export const MilestoneDef = {
    name: 'Milestone',
    tag: 'rui-milestone',

    tokens: {
        prefix: 'ms',
        tokens: {
            'marker-size':      { value: '2rem',             description: 'Marker circle size' },
            'marker-size-sm':   { value: '1.5rem',           description: 'Small marker size' },
            'connector':        { value: '2px',              description: 'Connector line thickness' },
            'font-size':        { ref: 'font.size-sm',       description: 'Step label font size' },
            'desc-font-size':   { value: '0.75rem',          description: 'Description font size' },
            'gap':              { ref: 'spacing.2',          description: 'Gap between marker and label' },
            'accent':           { ref: 'color.accent',       description: 'Active/completed accent' },
            'bg':               { ref: 'color.bg-raised',    description: 'Marker background' },
            'border':           { ref: 'color.border',       description: 'Default border/connector' },
            'text':             { ref: 'color.text',         description: 'Active step text' },
            'text-muted':       { ref: 'color.text-muted',   description: 'Inactive step text' },
            'error':            { ref: 'color.danger',       description: 'Error state color' },
        },
    },

    states: {
        initial: 'idle',
        states: {
            idle: {},
        },
    },

    template: {
        slots: {
            root:      { element: 'div', classes: ['milestone'],          role: 'list' },
            step:      { element: 'div', classes: ['milestone-step'],     role: 'listitem' },
            marker:    { element: 'div', classes: ['milestone-marker'] },
            content:   { element: 'div', classes: ['milestone-content'] },
            title:     { element: 'div', classes: ['milestone-title'] },
            desc:      { element: 'div', classes: ['milestone-desc'] },
        },
    },

    // ═══════════════════════════════════════
    //  JIT Parts
    // ═══════════════════════════════════════
    jitParts: {
        [PART.ROOT]:    PART.ROOT,
        [PART.STEP]:    PART.STEP,
        [PART.MARKER]:  PART.MARKER,
        [PART.CONTENT]: PART.CONTENT,
        [PART.TITLE]:   PART.TITLE,
        [PART.DESC]:    PART.DESC,
    },

    styles: {},

    observedAttrs: ['active', 'direction'],
    attrMap: {
        active: 'active',
        direction: 'direction',
    },
};

export default MilestoneDef;
