/**
 * @fileoverview Milestone constants — CSS classes, PART entities, JIT styles.
 * @module module/Milestone/constants
 */

import { defineParts } from '../shared/definePart.js';

/** CSS class names */
export const CLS = Object.freeze({
    ROOT:        'milestone',
    VERTICAL:    'is-vertical',
    STEP:        'milestone-step',
    CONNECTOR:   'milestone-connector',
    MARKER:      'milestone-marker',
    CONTENT:     'milestone-content',
    TITLE:       'milestone-title',
    DESC:        'milestone-desc',
    COMPLETED:   'is-completed',
    ACTIVE:      'is-active',
    ERROR:       'is-error',
    CLICKABLE:   'is-clickable',
    SMALL:       'is-small',
});

/** Semantic PART entities for JIT styling. */
export const PART = defineParts('Milestone', {
    ROOT:    { class: 'milestone', aliases: ['root', 'container'] },
    STEP:    { class: 'milestone-step', aliases: ['step'] },
    MARKER:  { class: 'milestone-marker', aliases: ['marker'] },
    CONTENT: { class: 'milestone-content', aliases: ['content'] },
    TITLE:   { class: 'milestone-title', aliases: ['title'] },
    DESC:    { class: 'milestone-desc', aliases: ['desc'] },
});

// ─── Self JIT (own element styles) ────────────────────────────────────

PART.ROOT.jit = 'flex items-start w-full [font-family:inherit] text-[.85rem]'
    + ' {is-vertical}:flex-col {is-vertical}:items-start';

PART.STEP.jit = 'flex flex-col items-center flex-1 relative text-center min-w-0'
    + ' not-first:before:absolute not-first:before:[top:1rem] not-first:before:[right:calc(50%_+_1rem_+_4px)] not-first:before:[left:calc(-50%_+_1rem_+_4px)] not-first:before:[height:2px] not-first:before:[background:var(--rui-border)] not-first:before:[z-index:0]'
    + ' {is-completed}:not-first:before:[background:var(--rui-accent)] {is-active}:not-first:before:[background:var(--rui-accent)]';

PART.MARKER.jit = 'flex items-center justify-center w-[2rem] h-[2rem] rounded-[50%] [border:2px_solid_var(--rui-border)] bg-[var(--rui-bg-raised)] fg-[var(--rui-text-muted)] text-[.8rem] fw-600 relative [z-index:1] shrink-0 [transition:background_.2s,border-color_.2s,color_.2s] [line-height:1] text-center overflow-hidden';

PART.CONTENT.jit = '[margin-top:.5rem] [max-width:100%] min-w-0';

PART.TITLE.jit = 'fw-600 fg-[var(--rui-text-muted)] [line-height:1.3] text-nowrap overflow-hidden [text-overflow:ellipsis]';

PART.DESC.jit = 'text-[.75rem] fg-[var(--rui-text-muted)] [line-height:1.4] [margin-top:.15rem]';

// ─── Marker: icon <i> centering ───────────────────────────────────────

PART.MARKER.bindChildJIT('i', 'absolute [top:50%] [left:50%] [transform:translate(-50%,-50%)] [line-height:1] [font-size:inherit]');

// ─── Step states → Marker ─────────────────────────────────────────────

PART.STEP.bindChildJIT(PART.MARKER, 'bg-[var(--rui-accent)] [border-color:var(--rui-accent)] fg-[#fff]', {
    when: 'is-completed',
});
PART.STEP.bindChildJIT(PART.MARKER, '[border-color:var(--rui-accent)] fg-[var(--rui-accent)] [box-shadow:0_0_0_3px_var(--rui-accent-subtle)]', {
    when: 'is-active',
});
PART.STEP.bindChildJIT(PART.MARKER, '[border-color:var(--rui-danger)] fg-[var(--rui-danger)] [box-shadow:0_0_0_3px_var(--rui-danger-subtle)]', {
    when: 'is-error',
});

// ─── Step states → Title ──────────────────────────────────────────────

PART.STEP.bindChildJIT(PART.TITLE, 'fg-[var(--rui-text)]', { when: 'is-completed' });
PART.STEP.bindChildJIT(PART.TITLE, 'fg-[var(--rui-text)]', { when: 'is-active' });
PART.STEP.bindChildJIT(PART.TITLE, 'fg-[var(--rui-danger)]', { when: 'is-error' });

// ─── Clickable → Marker hover/active ─────────────────────────────────

PART.STEP.bindChildJIT(PART.MARKER, '[border-color:var(--rui-accent)] fg-[var(--rui-accent)]', {
    when: 'is-clickable', pseudo: ':hover',
});
PART.STEP.bindChildJIT(PART.MARKER, '[transform:scale(0.92)]', {
    when: 'is-clickable', pseudo: ':active',
});

// ─── ROOT small variant → Marker/Step ─────────────────────────────────

PART.ROOT.bindChildJIT(PART.MARKER, '[width:1.5rem] [height:1.5rem] [font-size:.7rem]', {
    when: 'is-small',
});
PART.ROOT.bindChildJIT('.milestone-step:not(:first-child)::before', '[top:.75rem] [right:calc(-50%+.75rem+4px)] [left:calc(-50%+.75rem+4px)]', {
    when: 'is-small',
});

// ─── ROOT vertical variant ────────────────────────────────────────────

PART.ROOT.bindChildJIT(PART.STEP, '[flex-direction:row] items-start [text-align:left] [flex:none] w-full [padding-bottom:1.5rem]', {
    when: 'is-vertical',
});
PART.ROOT.bindChildJIT('.milestone-step:last-child', '[padding-bottom:0]', {
    when: 'is-vertical',
});
PART.ROOT.bindChildJIT('.milestone-step:not(:first-child)::before', '[display:none]', {
    when: 'is-vertical',
});

// Vertical connector (::after on non-last steps)
PART.ROOT.bindChildJIT('.milestone-step:not(:last-child)::after',
    'content-empty absolute [top:calc(2rem+4px)] [bottom:4px] [left:calc(1rem-1px)] [width:2px] [height:auto] bg-[var(--rui-border)] [z-index:0]', {
    when: 'is-vertical',
});
PART.ROOT.bindChildJIT('.milestone-step.is-completed:not(:last-child)::after',
    'bg-[var(--rui-accent)]', {
    when: 'is-vertical',
});

PART.ROOT.bindChildJIT(PART.CONTENT, '[margin-top:0] [margin-left:.75rem] [padding-top:.15rem]', {
    when: 'is-vertical',
});

// Vertical + small connector offsets
PART.ROOT.bindChildJIT('.milestone-step:not(:last-child)::after',
    '[top:calc(1.5rem+4px)] [left:calc(.75rem-1px)]', {
    when: 'is-vertical is-small',
});
